from math import *

n, m = map(int, input().split())
pts = [tuple(map(float, input().split())) for _ in range(n)]

def dist(a, b):
    return sqrt((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2)

def vec(a, b):
    return (b[0] - a[0], b[1] - a[1])

def dot(a, b):
    return a[0] * b[0] + a[1] * b[1]

def cross(a, b):
    return a[0] * b[1] - a[1] * b[0]

def proj(a, b):
    return dot(a, b) / dot(b, b) * b

def seg_intersect(a, b, c, d):
    v1 = vec(a, b)
    v2 = vec(c, d)
    v3 = vec(a, c)

    if cross(v1, v2) == 0:
        return None

    t = cross(v2, v3) / cross(v1, v2)
    u = cross(v1, v3) / cross(v1, v2)
    if 0 <= t <= 1 and 0 <= u <= 1:
        return (a[0] + t * v1[0], a[1] + t * v1[1])
    return None

def seg_len(a, b):
    return sqrt((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2)

def solve(a, b):
    res = 0
    for i in range(n):
        p = pts[i]
        q = pts[(i + 1) % n]
        c = seg_intersect(a, b, p, q)
        if c is not None:
            res += dist(c, p)
            a = c
        res += dist(p, q)
    return res

for _ in range(m):
    a, b, c, d = map(float, input().split())
    print(solve((a, b), (c, d)))
